// ── Product Catalog Schema + Curated Data ──────────────────────────
// 100+ products curated for Present Agent's gift recommendation engine.
// Every product is enriched with gift intelligence metadata that encodes
// relationship psychology, giver motivations, and recipient fit.
//
// Sources: Web research (Mar 2026), verified Canadian pricing + shipping.
// Products are chosen for giftability, not just quality — each one must
// make sense as something you'd give someone, not just buy for yourself.

export interface Product {
  id: string;
  name: string;
  brand: string;
  price: number; // CAD
  currency: "CAD";
  category: "practical" | "experiential" | "consumable" | "artisan" | "wellness" | "kids";
  imageUrl: string;
  buyUrl: string;
  shortDescription: string;

  // Qualitative metadata for relationship-context matching
  meta: {
    psychologicalFit: ("practical" | "thoughtful" | "playful" | "luxurious" | "sentimental" | "adventurous")[];
    relationshipFit: ("partner" | "parent" | "child" | "close_family" | "friend" | "professional" | "acquaintance")[];
    recipientTraits: string[];
    recipientAge?: string[]; // "0-2" | "3-5" | "6-11" | "12-17" | "18-25" | "26-40" | "41-60" | "61+"
    occasionFit: ("birthday" | "mothers_day" | "fathers_day" | "anniversary" | "thank_you" | "housewarming" | "wedding" | "graduation" | "retirement" | "christmas" | "valentines" | "just_because" | "baby_shower" | "new_baby")[];
    effortSignal: "low_effort" | "moderate_effort" | "high_effort";
    priceTier: "token" | "budget" | "moderate" | "premium" | "luxury";
    giftable: true;
    isLastMinute?: boolean; // Digital/instant delivery
    usageSignal?: string; // "She'll use this every morning"
    whatThisSays?: string; // "This says: 'I see your daily ritual'"
  };
}

export type PriceTier = Product["meta"]["priceTier"];

export function priceTierFromBudget(budget: string | undefined): PriceTier[] {
  if (!budget) return ["token", "budget", "moderate", "premium", "luxury"];
  const nums = budget.match(/\d+/g)?.map(Number) || [];
  const max = nums.length > 0 ? Math.max(...nums) : 0;
  if (max <= 25) return ["token"];
  if (max <= 50) return ["token", "budget"];
  if (max <= 100) return ["token", "budget", "moderate"];
  if (max <= 200) return ["budget", "moderate", "premium"];
  if (max <= 400) return ["moderate", "premium", "luxury"];
  return ["premium", "luxury"];
}

