// ── Catalog helpers ────────────────────────────────────────────────

export function getProductById(id: string): Product | undefined {
  return CATALOG.find((p) => p.id === id);
}

export function filterByPriceTier(tiers: PriceTier[]): Product[] {
  return CATALOG.filter((p) => tiers.includes(p.meta.priceTier));
}

export function filterByOccasion(occasion: string): Product[] {
  const normalized = occasion.toLowerCase().replace(/[^a-z_]/g, "_");
  return CATALOG.filter((p) =>
    p.meta.occasionFit.some((o) => normalized.includes(o.replace("_", "")))
  );
}

export function filterByCategory(category: Product["category"]): Product[] {
  return CATALOG.filter((p) => p.category === category);
}

export function filterByAge(ageRange: string): Product[] {
  return CATALOG.filter((p) =>
    p.meta.recipientAge?.includes(ageRange)
  );
}

// Catalog stats
export function getCatalogStats() {
  const categories: Record<string, number> = {};
  const priceTiers: Record<string, number> = {};
  for (const p of CATALOG) {
    categories[p.category] = (categories[p.category] || 0) + 1;
    priceTiers[p.meta.priceTier] = (priceTiers[p.meta.priceTier] || 0) + 1;
  }
  return { total: CATALOG.length, categories, priceTiers };
}
